102→function langName(code: string): string {
103→  const lang = SUPPORTED_LANGUAGES.find(l => l.code === code);
104→  return lang?.name ?? code;
105→}
106→
107→type TranslatorSubView = 'translate' | 'history';
108→
109→export function TranslatorView() {
110→  const nav = useNavigation();
111→  const [subView, setSubView] = useState<TranslatorSubView>('translate');
112→  const [sourceText, setSourceText] = useState('');
113→  const [sourceLang, setSourceLang] = useState('auto');
114→  const [targetLang, setTargetLang] = useState('es');
115→  const [detectedLang, setDetectedLang] = useState<string | undefined>();
116→  const [history, setHistory] = useState<TranslationHistoryEntry[]>(() =>
117→    MOCK_HISTORY.map(e => ({ ...e })));
118→  const [historyQuery, setHistoryQuery] = useState('');
119→  const [selectedIndex, setSelectedIndex] = useState(0);
120→  const [actionsOpen, setActionsOpen] = useState(false);
121→  const { items: hudItems, show: showHUD } = useHUD();
122→  const textareaRef = useRef<HTMLTextAreaElement>(null);
123→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
124→  const [translatedText, setTranslatedText] = useState('');
125→
126→  useEffect(() => {
127→    if (debounceRef.current) clearTimeout(debounceRef.current);
128→    if (!sourceText.trim()) {
129→      setTranslatedText('');
130→      setDetectedLang(undefined);
131→      return;
132→    }
133→    debounceRef.current = setTimeout(() => {
134→      const result = mockTranslate(sourceText, sourceLang, targetLang);
135→      setTranslatedText(result.translated);
136→      setDetectedLang(result.detectedLang);
137→    }, 300);
138→    return () => {
139→      if (debounceRef.current) clearTimeout(debounceRef.current);
140→    };
141→  }, [
142→    sourceText,
143→    sourceLang,
144→    targetLang,
145→  ]);
146→
147→  const filteredHistory = useMemo(() => {
148→    if (!historyQuery) return history;
149→    return history.filter(
150→      e =>
151→        fuzzyMatch(historyQuery, e.sourceText) ||
152→        fuzzyMatch(historyQuery, e.translatedText),
153→    );
154→  }, [
155→    history,
156→    historyQuery,
157→  ]);
158→
159→  const targetLangSections = useMemo(
160→    () => [
161→      {
162→        options: TARGET_LANGUAGES.map(l => ({
163→          value: l.code,
164→          label: l.name,
165→        })),
166→      },
167→    ],
168→    [],
169→  );
170→
171→  const handleSwapLanguages = useCallback(() => {
172→    if (sourceLang === 'auto') return;
173→    const prevSource = sourceLang;
174→    const prevTarget = targetLang;
175→    const prevTranslated = translatedText;
176→    setSourceLang(prevTarget);
177→    setTargetLang(prevSource);
178→    setSourceText(prevTranslated);
179→    setDetectedLang(undefined);
180→  }, [
181→    sourceLang,
182→    targetLang,
183→    translatedText,
184→  ]);
185→
186→  const handleCopyTranslation = useCallback(() => {
187→    if (!translatedText) return;
188→    setActionsOpen(false);
189→    performCopy(translatedText, showHUD, {
190→      hudIcon: <TranslateHUDIcon />,
191→      hudTitle: 'Translation Copied',
192→    });
193→  }, [
194→    translatedText,
195→    showHUD,
196→  ]);
197→
198→  const handleCopySource = useCallback(() => {
199→    if (!sourceText) return;
200→    setActionsOpen(false);
201→    performCopy(sourceText, showHUD, {
202→      hudIcon: <TranslateHUDIcon />,
203→      hudTitle: 'Source Copied',
204→    });
205→  }, [
206→    sourceText,
207→    showHUD,
208→  ]);
209→
210→  const handleSaveToHistory = useCallback(() => {
211→    if (!sourceText.trim() || !translatedText.trim()) return;
212→    const entry: TranslationHistoryEntry = {
213→      id: crypto.randomUUID(),
214→      sourceText: sourceText.trim(),
215→      translatedText: translatedText.trim(),
216→      sourceLang: detectedLang ?? sourceLang,
217→      targetLang,
218→      detectedLang,
219→      createdAt: new Date(),
220→    };
221→    setHistory(prev => [
222→      entry,
223→      ...prev,
224→    ]);
225→    showHUD({
226→      icon: <TranslateHUDIcon />,
227→      title: 'Saved to History',
228→    });
229→  }, [
230→    sourceText,
231→    translatedText,
232→    sourceLang,
233→    targetLang,
234→    detectedLang,
235→    showHUD,
236→  ]);
237→
238→  const handleClearSource = useCallback(() => {
239→    setSourceText('');
240→    setTranslatedText('');
241→    setDetectedLang(undefined);
242→    textareaRef.current?.focus();
243→  }, []);
244→
245→  const handleShowHistory = useCallback(() => {
246→    setActionsOpen(false);
247→    setSubView('history');
248→    setHistoryQuery('');
249→    setSelectedIndex(0);
250→  }, []);
251→
252→  const handleBackToTranslate = useCallback(() => {
253→    setSubView('translate');
254→  }, []);
255→
256→  const handleHistoryQueryChange = useCallback((value: string) => {
257→    setHistoryQuery(value);
258→    setSelectedIndex(0);
259→    setActionsOpen(false);
260→  }, []);
261→
262→  const handleActiveIndexChange = useCallback((index: number) => {
263→    setSelectedIndex(index);
264→    setActionsOpen(false);
265→  }, []);
266→
267→  const handleHistorySelect = useCallback(() => {
268→    const entry = filteredHistory[selectedIndex];
269→    if (!entry) return;
270→    setSourceText(entry.sourceText);
271→    setSourceLang(entry.sourceLang);
272→    setTargetLang(entry.targetLang);
273→    setSubView('translate');
274→  }, [
275→    filteredHistory,
276→    selectedIndex,
277→  ]);
278→
279→  const handleHistoryCopy = useCallback(() => {
280→    const entry = filteredHistory[selectedIndex];
281→    if (!entry) return;
282→    setActionsOpen(false);
283→    performCopy(entry.translatedText, showHUD, {
284→      hudIcon: <TranslateHUDIcon />,
285→      hudTitle: 'Translation Copied',
286→    });
287→  }, [
288→    filteredHistory,
289→    selectedIndex,
290→    showHUD,
291→  ]);
292→
293→  const toggleActions = useCallback(() => {
294→    setActionsOpen(prev => !prev);
295→  }, []);
296→
297→  const closeActions = useCallback(() => {
298→    setActionsOpen(false);
299→  }, []);
300→
301→  useKeyboardShortcut(
302→    {
303→      key: 'k',
304→      meta: true,
305→    },
306→    toggleActions,
307→  );
308→  useKeyboardShortcut(
309→    {
310→      key: 'c',
311→      meta: true,
312→    },
313→    subView === 'translate' ? handleCopyTranslation : handleHistoryCopy,
314→  );
315→  useKeyboardShortcut(
316→    {
317→      key: 's',
318→      meta: true,
319→    },
320→    handleSaveToHistory,
321→    { enabled: subView === 'translate' },
322→  );
323→  useKeyboardShortcut(
324→    {
325→      key: 'h',
326→      meta: true,
327→      shift: true,
328→    },
329→    handleShowHistory,
330→    { enabled: subView === 'translate' },
331→  );
332→  useKeyboardShortcut({ key: 'Escape' }, handleBackToTranslate, {
333→    enabled: subView === 'history',
334→    preventDefault: false,
335→  });
336→
337→  if (subView === 'history') {
338→    const totalItemCount = filteredHistory.length;
339→    const renderNow = new Date();
340→    const activeDescendantId =
341→      totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;
342→
343→    const historyDropdownSections: DropdownSection[] = [
344→      {
345→        title: 'Actions',
346→        actions: [
347→          {
348→            label: 'Use Translation',
349→            shortcut: <Kbd keys={['↵']} />,
350→            onClick: handleHistorySelect,
351→          },
352→          createCopyAction(
353→            {
354→              content: filteredHistory[selectedIndex]?.translatedText ?? '',
355→              title: 'Copy Translation',
356→              shortcut: (
357→                <Kbd
358→                  keys={[
359→                    '⌘',
360→                    'C',
361→                  ]}
362→                />
363→              ),
364→              hudIcon: <TranslateHUDIcon />,
365→            },
366→            showHUD,
367→          ),
368→        ],
369→      },
370→    ];
371→
372→    return (
373→      <>
374→        <SearchBar
375→          value={historyQuery}
376→          onChange={handleHistoryQueryChange}
377→          placeholder="Search History..."
378→          activeDescendantId={activeDescendantId}
379→          breadcrumbs={[
380→            ...nav.breadcrumbs,
381→            {
382→              label: 'Translate',
383→              onBack: handleBackToTranslate,
384→            },
385→          ]}
386→        />
387→        <div className="command-palette__body">
388→          <div className="command-palette__list-container">
389→            {totalItemCount === 0 ? (
390→              <EmptyState
391→                icon={<TranslateEmptyIcon />}
392→                title="No History"
393→                description={
394→                  historyQuery
395→                    ? 'Try a different search term'
396→                    : 'Translations you save will appear here'
397→                }
398→              />
399→            ) : (
400→              <List
401→                itemCount={totalItemCount}
402→                onActiveIndexChange={handleActiveIndexChange}
403→                onAction={handleHistorySelect}
404→              >
405→                <ListSection title="Translation History">
406→                  {filteredHistory.map((entry, idx) => (
407→                    <ListItem
408→                      key={entry.id}
409→                      index={idx}
410→                      icon={<GlobeIcon />}
411→                      title={entry.sourceText}
412→                      subtitle={entry.translatedText}
413→                      accessories={[
414→                        {
415→                          tag: {
416→                            text: `${langName(entry.sourceLang)} \u2192 ${langName(entry.targetLang)}`,
417→                          },
418→                        },
419→                        {
420→                          text: formatRelativeDate(entry.createdAt, renderNow),
421→                          tooltip: entry.createdAt.toLocaleString(),
422→                        },
423→                      ]}
424→                      query={historyQuery || undefined}
425→                    />
426→                  ))}
427→                </ListSection>
428→              </List>
429→            )}
430→          </div>
431→        </div>
432→        <ActionPanel
433→          contextLabel="History"
434→          actions={[
435→            {
436→              label: 'Use',
437→              shortcut: <Kbd keys={['\u21B5']} />,
438→            },
439→            {
440→              label: 'Actions',
441→              shortcut: (
442→                <Kbd
443→                  keys={[
444→                    '\u2318',
445→                    'K',
446→                  ]}
447→                />
448→              ),
449→            },
450→          ]}
451→          dropdownOpen={actionsOpen}
452→          dropdownSections={historyDropdownSections}
453→          onDropdownClose={closeActions}
454→        />
455→        <HUDContainer items={hudItems} />
456→      </>
457→    );
458→  }
459→
460→  const sourceDisplayLang =
461→    sourceLang === 'auto'
462→      ? detectedLang
463→        ? langName(detectedLang)
464→        : 'Detect Language'
465→      : langName(sourceLang);
466→
467→  const translateDropdownSections: DropdownSection[] = [
468→    {
469→      title: 'Actions',
470→      actions: [
471→        createCopyAction(
472→          {
473→            content: translatedText,
474→            title: 'Copy Translation',
475→            shortcut: (
476→              <Kbd
477→                keys={[
478→                  '\u2318',
479→                  'C',
480→                ]}
481→              />
482→            ),
483→            hudIcon: <TranslateHUDIcon />,
484→          },
485→          showHUD,
486→        ),
487→        {
488→          label: 'Copy Source',
489→          onClick: handleCopySource,
490→        },
491→        {
492→          label: 'Save to History',
493→          shortcut: (
494→            <Kbd
495→              keys={[
496→                '\u2318',
497→                'S',
498→              ]}
499→            />
500→          ),
501→          onClick: handleSaveToHistory,
502→        },
503→        {
504→          label: 'Swap Languages',
505→          onClick: handleSwapLanguages,
506→        },
507→        {
508→          label: 'Clear',
509→          onClick: handleClearSource,
510→        },
511→      ],
512→    },
513→    {
514→      title: 'Navigation',
515→      actions: [
516→        {
517→          label: 'Translation History',
518→          shortcut: (
519→            <Kbd
520→              keys={[
521→                '\u2318',
522→                '\u21E7',
523→                'H',
524→              ]}
525→            />
526→          ),
527→          onClick: handleShowHistory,
528→        },
529→      ],
530→    },
531→  ];
532→
533→  return (
534→    <>
535→      <SearchBar
536→        value=""
537→        onChange={() => {}}
538→        placeholder="Translate"
539→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
540→        dropdown={
541→          <SearchDropdown
542→            sections={targetLangSections}
543→            value={targetLang}
544→            onChange={setTargetLang}
545→          />
546→        }
547→      />
548→      <div className="command-palette__body">
549→        <div className="command-palette__list-container">
550→          <div className="translator">
551→            <div className="translator__panels">
552→              <div className="translator__panel">
553→                <div className="translator__panel-header">
554→                  <span className="translator__lang-label">
555→                    {sourceDisplayLang}
556→                  </span>
557→                  {sourceLang === 'auto' && detectedLang && (
558→                    <span className="translator__detected-badge">Detected</span>
559→                  )}
560→                </div>
561→                <textarea
562→                  ref={textareaRef}
563→                  className="translator__textarea"
564→                  value={sourceText}
565→                  onChange={e => setSourceText(e.target.value)}
566→                  placeholder="Enter text to translate..."
567→                  aria-label="Source text"
568→                  autoFocus
569→                />
570→                {sourceText && (
571→                  <div className="translator__char-count">
572→                    {sourceText.length} characters
573→                  </div>
574→                )}
575→              </div>
576→              <div className="translator__divider">
577→                <button
578→                  className="translator__swap-button"
579→                  onClick={handleSwapLanguages}
580→                  disabled={sourceLang === 'auto'}
581→                  aria-label="Swap languages"
582→                  type="button"
583→                >
584→                  <SwapIcon />
585→                </button>
586→              </div>
587→              <div className="translator__panel">
588→                <div className="translator__panel-header">
589→                  <span className="translator__lang-label">
590→                    {langName(targetLang)}
591→                  </span>
592→                </div>
593→                <div className="translator__output" aria-live="polite">
594→                  {translatedText ? (
595→                    translatedText
596→                  ) : (
597→                    <span className="translator__output-placeholder">
598→                      Translation will appear here...
599→                    </span>
600→                  )}
601→                </div>
602→              </div>
603→            </div>
604→          </div>
605→        </div>
606→      </div>
607→      <ActionPanel
608→        contextLabel="Translate"
609→        actions={[
610→          {
611→            label: 'Copy Translation',
612→            shortcut: (
613→              <Kbd
614→                keys={[
615→                  '\u2318',
616→                  'C',
617→                ]}
618→              />
619→            ),
620→          },
621→          {
622→            label: 'Actions',
623→            shortcut: (
624→              <Kbd
625→                keys={[
626→                  '\u2318',
627→                  'K',
628→                ]}
629→              />
630→            ),
631→          },
632→        ]}
633→        dropdownOpen={actionsOpen}
634→        dropdownSections={translateDropdownSections}
635→        onDropdownClose={closeActions}
636→      />
637→      <HUDContainer items={hudItems} />
638→    </>
639→  );
640→}
